const order = $input.first().json;

const shopName = "NovaStore";
const invoiceNo = order.number;
const orderDate = new Date(order.date_created).toLocaleString();
const paymentMethod = order.payment_method_title;

const currencyCode = order.currency || "BDT";

const billing = order.billing;
const shipping = order.shipping;

let itemsHtml = '';
order.line_items.forEach(item => {
  itemsHtml += `
    <tr>
      <td style="padding: 12px; border-bottom: 1px solid #eee;">
        ${item.name} <br>
        <span style="color: #888; font-size: 12px;">SKU: ${item.sku}</span>
      </td>
      <td style="padding: 12px; border-bottom: 1px solid #eee; text-align: center;">${item.quantity}</td>
      <td style="padding: 12px; border-bottom: 1px solid #eee; text-align: right;">${parseFloat(item.price).toFixed(2)} ${currencyCode}</td>
      <td style="padding: 12px; border-bottom: 1px solid #eee; text-align: right; font-weight: 500;">${parseFloat(item.total).toFixed(2)} ${currencyCode}</td>
    </tr>
  `;
});

const totalTax = parseFloat(order.total_tax || 0);
const discountTotal = parseFloat(order.discount_total || 0);
const shippingTotal = parseFloat(order.shipping_total || 0);
const grandTotal = parseFloat(order.total);

const subTotal = grandTotal - shippingTotal - totalTax;

let taxRowHtml = '';
if (totalTax > 0) {
  taxRowHtml = `
    <div class="totals-row">
      <span>Tax:</span>
      <span>${totalTax.toFixed(2)} ${currencyCode}</span>
    </div>
  `;
}

let discountRowHtml = '';
if (discountTotal > 0) {
  discountRowHtml = `
    <div class="totals-row" style="color: #e74c3c;">
      <span>Discount:</span>
      <span> - ${discountTotal.toFixed(2)} ${currencyCode}</span>
    </div>
  `;
}


const htmlTemplate = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; color: #333; margin: 0; padding: 40px; background-color: #f9f9f9; }
    .container { max-width: 800px; margin: 0 auto; background: #fff; padding: 40px; border-radius: 8px; box-shadow: 0 0 15px rgba(0,0,0,0.05); border-top: 6px solid #4A90E2; }
    .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 40px; }
    .shop-name { font-size: 32px; font-weight: bold; color: #2c3e50; margin: 0; }
    .invoice-title { font-size: 24px; color: #7f8c8d; margin: 0; text-transform: uppercase; letter-spacing: 2px; }
    .invoice-meta { margin-top: 20px; font-size: 14px; color: #555; }
    .invoice-meta strong { color: #2c3e50; }

    .customer-section { display: flex; justify-content: space-between; margin-bottom: 40px; }
    .section-box { width: 48%; }
    .section-title { font-size: 14px; font-weight: bold; color: #4A90E2; text-transform: uppercase; margin-bottom: 10px; border-bottom: 2px solid #eee; padding-bottom: 5px; }
    .section-content { font-size: 14px; line-height: 1.6; color: #555; }

    table { width: 100%; border-collapse: collapse; margin-bottom: 30px; }
    th { background-color: #f8f9fa; padding: 12px; text-align: left; font-size: 13px; color: #666; border-bottom: 2px solid #ddd; text-transform: uppercase; }
    th:last-child, td:last-child { text-align: right; }
    th:nth-child(2), td:nth-child(2) { text-align: center; }

    .totals-section { width: 50%; margin-left: auto; font-size: 14px; }
    .totals-row { display: flex; justify-content: space-between; padding: 8px 0; border-bottom: 1px solid #eee; }
    .grand-total { font-size: 18px; font-weight: bold; color: #2c3e50; border-bottom: none; margin-top: 10px; padding-top: 10px; border-top: 2px solid #333; }

    .footer { margin-top: 50px; text-align: center; font-size: 12px; color: #999; border-top: 1px solid #eee; padding-top: 20px; }
  </style>
</head>
<body>
  <div class="container">

    <!-- Header Section -->
    <div class="header">
      <div>
        <h1 class="shop-name">${shopName}</h1>
        <p style="color: #777; margin: 5px 0 0 0;">Dhaka, Bangladesh</p>
        <p style="color: #777; margin: 5px 0 0 0;">Email: support@novastore.com</p>
      </div>
      <div style="text-align: right;">
        <h2 class="invoice-title">Invoice</h2>
        <div class="invoice-meta">
          <strong>Invoice #:</strong> ${invoiceNo}<br>
          <strong>Date:</strong> ${orderDate}<br>
          <strong>Payment:</strong> ${paymentMethod}
        </div>
      </div>
    </div>

    <!-- Customer Info Section -->
    <div class="customer-section">
      <div class="section-box">
        <div class="section-title">Bill To</div>
        <div class="section-content">
          <strong>${billing.first_name} ${billing.last_name}</strong><br>
          ${billing.address_1}<br>
          ${billing.city}, ${billing.state}<br>
          ${billing.country}<br>
          Phone: ${billing.phone}<br>
          Email: ${billing.email}
        </div>
      </div>
      <div class="section-box">
        <div class="section-title">Ship To</div>
        <div class="section-content">
          <strong>${shipping.first_name} ${shipping.last_name}</strong><br>
          ${shipping.address_1}<br>
          ${shipping.city}, ${shipping.state}<br>
          ${shipping.country}<br>
          Phone: ${shipping.phone}
        </div>
      </div>
    </div>

    <!-- Items Table -->
    <table>
      <thead>
        <tr>
          <th>Product Description</th>
          <th>Qty</th>
          <th>Unit Price</th>
          <th>Total</th>
        </tr>
      </thead>
      <tbody>
        ${itemsHtml}
      </tbody>
    </table>

    <!-- Totals Section -->
    <div class="totals-section">
      <div class="totals-row">
        <span>Subtotal:</span>
        <span>${subTotal.toFixed(2)} ${currencyCode}</span>
      </div>

      ${discountRowHtml}

      <div class="totals-row">
        <span>Shipping:</span>
        <span>${shippingTotal.toFixed(2)} ${currencyCode}</span>
      </div>

      ${taxRowHtml}

      <div class="totals-row grand-total">
        <span>Grand Total:</span>
        <span>${grandTotal.toFixed(2)} ${currencyCode}</span>
      </div>
    </div>

    <!-- Footer -->
    <div class="footer">
      <p>Thank you for your purchase from ${shopName}!</p>
      <p>This is a computer-generated invoice and does not require a physical signature.</p>
    </div>

  </div>
</body>
</html>
`;

return {
  json: {
    invoice_html: htmlTemplate,
    order_id: invoiceNo,
    customer_name: `${billing.first_name} ${billing.last_name}`
  }
};

let totalOrders = 0;
let totalRefunds = 0;
let uniqueCustomers = new Set();
let customerOrderCount = {};
let productSales = {};
const orders = $input.all();
totalOrders = orders.length;
for (const item of orders) {
  const order = item.json;
  if (order.refunds && Array.isArray(order.refunds) && order.refunds.length > 0) {
    for (const refund of order.refunds) {
      totalRefunds += Math.abs(parseFloat(refund.total));
    }
  }
  const custId = order.customer_id;
  uniqueCustomers.add(custId);
  if (!customerOrderCount[custId]) {
    customerOrderCount[custId] = 0;
  }
  customerOrderCount[custId]++;
  if (order.line_items && Array.isArray(order.line_items)) {
    for (const line of order.line_items) {
      const pName = line.name;
      const qty = parseInt(line.quantity, 10);
      if (!productSales[pName]) {
        productSales[pName] = 0;
      }
      productSales[pName] += qty;
    }
  }
}
let newCustomersCount = 0;
let returningCustomersCount = 0;
for (const custId in customerOrderCount) {
  if (customerOrderCount[custId] === 1) {
    newCustomersCount++;
  } else {
    returningCustomersCount++;
  }
}
let bestSeller = "No sales yet";
let maxQty = 0;
for (const [name, qty] of Object.entries(productSales)) {
  if (qty > maxQty) {
    maxQty = qty;
    bestSeller = name;
  }
}
const today = new Date();
const year = today.getFullYear();
const month = String(today.getMonth() + 1).padStart(2, '0');
const day = String(today.getDate()).padStart(2, '0');
const reportDate = `${year}-${month}-${day}`;
return [
  {
    json: {
      date: reportDate,
      total_orders: totalOrders,
      total_refunds: totalRefunds.toFixed(2),
      total_unique_customers: uniqueCustomers.size,
      new_customers: newCustomersCount,
      returning_customers: returningCustomersCount,
      best_selling_product: bestSeller
    }
  }
];
